<!DOCTYPE html>
<html lang="id">
<head>
    <meta charset="utf-8">
    <meta name="viewport" content="width=device-width, initial-scale=1">
    <meta name="csrf-token" content="{{ csrf_token() }}">
    <title>Anjungan Mandiri - {{ $clinic->name }}</title>
    <link rel="preconnect" href="https://fonts.googleapis.com"><link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>
    <link href="https://fonts.googleapis.com/css2?family=DM+Sans:wght@400;500;600;700&family=Manrope:wght@600;700;800&display=swap" rel="stylesheet">
    <style>
        :root{--navy:#07182e;--blue:#176bda;--cyan:#17b7c8;--ink:#14213a;--muted:#6c7c94;--line:#dce7f3;--bg:#eef5fb;--green:#0b9f6e;--red:#d94b5b}*{box-sizing:border-box}body{margin:0;min-height:100vh;background:radial-gradient(circle at 90% 5%,rgba(23,183,200,.14),transparent 28%),linear-gradient(135deg,#f7fbff,#edf5fb);color:var(--ink);font-family:'DM Sans',sans-serif}.app{min-height:100vh;display:grid;grid-template-rows:auto 1fr}.topbar{height:76px;padding:0 clamp(22px,4vw,64px);display:flex;align-items:center;justify-content:space-between;background:rgba(255,255,255,.86);border-bottom:1px solid rgba(196,214,232,.8);backdrop-filter:blur(18px)}.brand{display:flex;align-items:center;gap:14px}.logo{width:44px;height:44px;border-radius:15px;background:linear-gradient(145deg,var(--blue),var(--cyan));display:grid;place-items:center;color:white;font:800 24px Manrope}.brand strong{font:800 20px Manrope}.brand small{display:block;color:var(--muted);margin-top:2px}.clock{text-align:right}.clock strong{font:800 22px Manrope}.clock span{display:block;color:var(--muted);font-size:11px}.content{width:min(1180px,calc(100% - 32px));margin:0 auto;padding:26px 0 42px}.hero{text-align:center;margin-bottom:22px}.hero h1{font:800 clamp(26px,3vw,42px) Manrope;margin:0}.hero p{color:var(--muted);margin:7px 0 0}.menus{display:grid;grid-template-columns:repeat(3,1fr);gap:12px;margin-bottom:20px}.menu{border:1px solid var(--line);border-radius:20px;padding:17px;background:white;color:var(--muted);font:700 14px 'DM Sans';cursor:pointer;box-shadow:0 10px 28px rgba(30,73,112,.06)}.menu.active{border-color:rgba(23,107,218,.4);background:linear-gradient(145deg,#176bda,#0d91c0);color:white;box-shadow:0 14px 34px rgba(23,107,218,.2)}.menu:disabled{cursor:not-allowed;opacity:.62}.panel{background:rgba(255,255,255,.94);border:1px solid var(--line);border-radius:28px;box-shadow:0 24px 70px rgba(27,65,101,.1);padding:clamp(20px,3vw,36px)}.section-title{display:flex;align-items:center;gap:12px;margin-bottom:20px}.step{width:32px;height:32px;border-radius:11px;background:#e8f2ff;color:var(--blue);display:grid;place-items:center;font-weight:800}.section-title h2{font:800 19px Manrope;margin:0}.section-title p{font-size:12px;color:var(--muted);margin:2px 0 0}.search{display:grid;grid-template-columns:180px 1fr 150px;gap:12px;align-items:end}.field label{display:block;font-size:11px;font-weight:700;color:#52647d;margin:0 0 7px;text-transform:uppercase;letter-spacing:.05em}input,select,textarea{width:100%;border:1px solid #cfdeec;border-radius:14px;background:#fbfdff;padding:13px 14px;color:var(--ink);font:600 14px 'DM Sans';outline:none;transition:.2s}input:focus,select:focus,textarea:focus{border-color:#4a98e8;box-shadow:0 0 0 4px rgba(74,152,232,.12)}button.primary{border:0;border-radius:14px;background:linear-gradient(145deg,var(--blue),#138ebd);color:white;font:700 14px 'DM Sans';padding:13px 18px;cursor:pointer}#search-button{height:46px;padding-top:0;padding-bottom:0}button.secondary{border:1px solid #b9d2eb;border-radius:14px;background:white;color:var(--blue);font:700 13px 'DM Sans';padding:12px 17px;cursor:pointer}.result{margin-top:20px}.hidden{display:none!important}.notice{padding:14px 16px;border-radius:15px;font-size:13px}.notice.error{background:#fff0f2;color:#a72f42;border:1px solid #f4c6cd}.participant{border:1px solid #b9ead9;background:linear-gradient(145deg,#f2fffa,#effbf9);border-radius:22px;padding:20px}.participant.inactive{border-color:#f0c3ca;background:#fff5f6}.participant-head{display:flex;justify-content:space-between;align-items:flex-start;gap:18px}.badge{border-radius:999px;padding:7px 11px;background:#d8f8eb;color:#087851;font-size:11px;font-weight:800}.inactive .badge{background:#ffe0e4;color:#ae3547}.participant h3{font:800 23px Manrope;margin:4px 0}.meta-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:10px;margin-top:15px}.meta{background:rgba(255,255,255,.75);border:1px solid rgba(181,215,204,.7);border-radius:14px;padding:11px}.meta span{display:block;font-size:10px;color:var(--muted);text-transform:uppercase}.meta b{display:block;font-size:13px;margin-top:4px;word-break:break-word}.patient-state{margin-top:14px;display:flex;align-items:center;justify-content:space-between;gap:14px;border-top:1px dashed #b6d9ce;padding-top:14px}.rm{font:800 20px Manrope;color:var(--green)}.form-card,.queue-card{margin-top:18px;border:1px solid var(--line);border-radius:20px;padding:20px;background:#f9fcff}.grid{display:grid;grid-template-columns:repeat(2,1fr);gap:13px}.grid .wide{grid-column:1/-1}.readonly{background:#eef4f9;color:#64748b}.actions{display:flex;justify-content:flex-end;gap:10px;margin-top:17px}.queue-grid{display:grid;grid-template-columns:1fr 1fr 160px;gap:12px;align-items:end}.success{margin-top:18px;border-radius:22px;padding:24px;background:linear-gradient(145deg,#0b9f6e,#0a8b87);color:white;text-align:center}.success strong{display:block;font:800 34px Manrope;margin-top:5px}.spinner{display:inline-block;width:17px;height:17px;border:2px solid rgba(255,255,255,.4);border-top-color:white;border-radius:50%;animation:spin .7s linear infinite;vertical-align:-4px;margin-right:7px}@keyframes spin{to{transform:rotate(360deg)}}@media(max-width:760px){.topbar{height:66px}.brand small,.clock span{display:none}.content{padding-top:18px}.menus{grid-template-columns:1fr}.search,.queue-grid{grid-template-columns:1fr}.meta-grid,.grid{grid-template-columns:1fr 1fr}.panel{border-radius:22px}}@media(max-width:480px){.meta-grid,.grid{grid-template-columns:1fr}.participant-head,.patient-state{flex-direction:column}.grid .wide{grid-column:auto}}
        .progress{display:grid;grid-template-columns:repeat(4,1fr);gap:8px;margin-bottom:24px}.progress-item{position:relative;text-align:center;color:#94a3b8;font-size:11px;font-weight:700;padding-top:34px}.progress-item:before{content:attr(data-number);position:absolute;top:0;left:50%;transform:translateX(-50%);width:27px;height:27px;border-radius:50%;display:grid;place-items:center;background:#e8eef5;color:#7b8ba2;z-index:2}.progress-item:not(:last-child):after{content:'';position:absolute;top:13px;left:calc(50% + 18px);width:calc(100% - 36px);height:2px;background:#e2eaf2}.progress-item.active{color:var(--blue)}.progress-item.active:before{background:var(--blue);color:white;box-shadow:0 0 0 5px rgba(23,107,218,.11)}.progress-item.done{color:var(--green)}.progress-item.done:before{content:'\2713';background:var(--green);color:white}.progress-item.done:after{background:#74cfb0}.stage{animation:stageIn .25s ease}.stage-header{display:flex;align-items:center;justify-content:space-between;gap:16px;margin-bottom:20px}.compact-person{display:flex;align-items:center;gap:12px;padding:11px 14px;border:1px solid var(--line);background:#f7fbff;border-radius:15px;margin-bottom:18px}.compact-person b{display:block}.compact-person span{font-size:11px;color:var(--muted)}.form-card,.queue-card{margin-top:0}.stage .success{margin-top:0}.back{white-space:nowrap}@keyframes stageIn{from{opacity:0;transform:translateY(7px)}to{opacity:1;transform:none}}@media(max-width:600px){.progress-item{font-size:9px}.progress-item span{display:none}.stage-header{align-items:flex-start}.content{width:min(100% - 20px,1180px)}}
    </style>
</head>
<body><div class="app">
<header class="topbar"><div class="brand"><div class="logo">+</div><div><strong>{{ $clinic->name }}</strong><small>Anjungan Pelayanan Mandiri</small></div></div><div class="clock"><strong id="clock">--:--</strong><span id="date"></span></div></header>
<main class="content"><div class="hero"><h1>Selamat Datang</h1><p>Silakan pilih layanan yang Anda butuhkan</p></div>
<div class="menus"><button class="menu active">Cek Nomor Peserta</button><button class="menu" disabled title="Segera tersedia">Ambil Antrean Langsung</button><button class="menu" disabled title="Segera tersedia">Cek Jadwal Dokter</button></div>
<section class="panel"><div id="progress" class="progress"></div><div id="error" class="notice error hidden"></div>
<div id="stage" class="stage"><div class="section-title"><div class="step">1</div><div><h2>Cek Kepesertaan BPJS</h2><p>Gunakan nomor kartu BPJS atau NIK peserta</p></div></div>
<form id="search-form" class="search"><div class="field"><label>Jenis Pencarian</label><select id="jenis"><option value="noka">No. Kartu BPJS</option><option value="nik">NIK</option></select></div><div class="field"><label>Nomor Identitas</label><input id="nomor" inputmode="numeric" pattern="[0-9]*" autocomplete="off" placeholder="Masukkan 13 digit No. Kartu" maxlength="13" required></div><button id="search-button" class="primary">Periksa Peserta</button></form></div>
</section></main></div>
<script>
const BASE_API_URL='https://www.emsifa.com/api-wilayah-indonesia/api';const csrf=document.querySelector('meta[name="csrf-token"]').content;const state={participant:null,token:null,patient:null,schedules:[]};const el=id=>document.getElementById(id);
const steps=['Cek Peserta','Data Peserta','Pilih Layanan','Selesai'];function setProgress(current){el('progress').innerHTML=steps.map((label,index)=>`<div class="progress-item ${index+1<current?'done':index+1===current?'active':''}" data-number="${index+1}"><span>${label}</span></div>`).join('')}function setStage(html,current){clearError();el('stage').innerHTML=html;setProgress(current)}function personSummary(){const p=state.participant;return `<div class="compact-person"><div><b>${esc(p.nama)}</b><span>${esc(p.noka)}${state.patient?` &nbsp;·&nbsp; RM ${esc(state.patient.no_rkm_medis)}`:''}</span></div></div>`}setProgress(1);
function clock(){const n=new Date();el('clock').textContent=n.toLocaleTimeString('id-ID',{hour:'2-digit',minute:'2-digit'}).replace('.',':');el('date').textContent=n.toLocaleDateString('id-ID',{weekday:'long',day:'2-digit',month:'long',year:'numeric'})}clock();setInterval(clock,1000);
function esc(v){const d=document.createElement('div');d.textContent=v??'-';return d.innerHTML}function showError(message){el('error').textContent=message;el('error').classList.remove('hidden')}function clearError(){el('error').classList.add('hidden')}
async function post(url,data){const response=await fetch(url,{method:'POST',headers:{'Content-Type':'application/json','Accept':'application/json','X-CSRF-TOKEN':csrf},body:JSON.stringify(data)});const json=await response.json().catch(()=>({message:'Respons server tidak dapat dibaca.'}));if(!response.ok||json.status===false)throw new Error(json.message||Object.values(json.errors||{}).flat()[0]||'Permintaan gagal.');return json}
function configureIdentityInput(){const nik=el('jenis').value==='nik',input=el('nomor');input.value=input.value.replace(/\D/g,'').slice(0,nik?16:13);input.maxLength=nik?16:13;input.placeholder=nik?'Masukkan 16 digit NIK':'Masukkan 13 digit No. Kartu'}el('jenis').addEventListener('change',()=>{el('nomor').value='';configureIdentityInput();el('nomor').focus()});el('nomor').addEventListener('input',configureIdentityInput);configureIdentityInput();
el('search-form').addEventListener('submit',async e=>{e.preventDefault();clearError();const jenis=el('jenis').value,nomor=el('nomor').value.replace(/\D/g,''),requiredLength=jenis==='nik'?16:13;if(nomor.length!==requiredLength){showError(`${jenis==='nik'?'NIK':'Nomor Kartu BPJS'} harus terdiri dari ${requiredLength} digit angka.`);return}const button=el('search-button');button.disabled=true;button.innerHTML='<span class="spinner"></span>Memeriksa';try{const data=await post('{{ route('kiosk.lookup') }}',{jenis,nomor});if(!data.participant)throw new Error('Data peserta tidak ditemukan pada respons BPJS.');state.participant=data.participant;state.token=data.participant_token;state.patient=data.patient;state.schedules=data.schedules||[];renderParticipant()}catch(error){state.participant=null;showError(error.message);button.disabled=false;button.textContent='Periksa Peserta'}});
function renderParticipant(){const p=state.participant;if(!p){showError('Data peserta belum tersedia. Silakan ulangi pencarian.');return}const active=Boolean(p.aktif);setStage(`<div class="stage-header"><div class="section-title" style="margin:0"><div class="step">2</div><div><h2>Data Peserta</h2><p>Pastikan data peserta berikut sudah benar</p></div></div><button class="secondary back" id="start-over">Periksa Ulang</button></div><div class="participant ${active?'':'inactive'}"><div class="participant-head"><div><span class="badge">${active?'PESERTA AKTIF':'PESERTA TIDAK AKTIF'}</span><h3>${esc(p.nama)}</h3><div style="color:var(--muted);font-size:13px">${esc(p.status)}</div></div></div><div class="meta-grid"><div class="meta"><span>No. Kartu</span><b>${esc(p.noka)}</b></div><div class="meta"><span>NIK</span><b>${esc(p.nik)}</b></div><div class="meta"><span>Jenis Kelamin</span><b>${p.jenis_kelamin==='P'?'Perempuan':'Laki-laki'}</b></div><div class="meta"><span>Tanggal Lahir</span><b>${esc(p.tanggal_lahir)}</b></div></div>${active?patientState():''}</div>`,2);el('start-over').onclick=()=>location.reload();if(active){if(!state.patient)el('create-rm')?.addEventListener('click',renderPatientForm);else{el('continue-queue')?.addEventListener('click',renderQueueForm)}}}
function patientState(){return `<div class="patient-state"><div>${state.patient?`<div style="font-size:11px;color:var(--muted)">NOMOR REKAM MEDIS</div><div class="rm">${esc(state.patient.no_rkm_medis)}</div>`:`<b>Nomor rekam medis belum tersedia</b><div style="font-size:12px;color:var(--muted);margin-top:3px">Buat data pasien sebelum mengambil antrean</div>`}</div>${state.patient?'<button id="continue-queue" class="primary">Lanjut Pilih Poli</button>':'<button id="create-rm" class="primary">Buat No. Rekam Medis</button>'}</div>`}
function renderPatientForm(){const p=state.participant;setStage(`${personSummary()}<form id="patient-form" class="form-card"><div class="stage-header"><div class="section-title" style="margin:0"><div class="step">3</div><div><h2>Buat Rekam Medis</h2><p>Lengkapi alamat domisili peserta</p></div></div><button type="button" id="cancel-rm" class="secondary back">Kembali</button></div><div class="grid"><div class="field"><label>NIK</label><input class="readonly" value="${esc(p.nik)}" readonly></div><div class="field"><label>No. Kartu BPJS</label><input class="readonly" value="${esc(p.noka)}" readonly></div><div class="field wide"><label>Nama Lengkap</label><input class="readonly" value="${esc(p.nama)}" readonly></div><div class="field"><label>Jenis Kelamin</label><input class="readonly" value="${p.jenis_kelamin==='P'?'Perempuan':'Laki-laki'}" readonly></div><div class="field"><label>Tanggal Lahir</label><input class="readonly" value="${esc(p.tanggal_lahir)}" readonly></div><div class="field wide"><label>No. HP</label><input class="readonly" value="${esc(p.no_hp||'-')}" readonly></div><div class="field"><label>Provinsi</label><select id="province" required><option value="">Memuat...</option></select></div><div class="field"><label>Kabupaten/Kota</label><select id="regency" required disabled><option value="">Pilih kabupaten</option></select></div><div class="field"><label>Kecamatan</label><select id="district" required disabled><option value="">Pilih kecamatan</option></select></div><div class="field"><label>Kelurahan/Desa</label><select id="village" required disabled><option value="">Pilih kelurahan</option></select></div><div class="field wide"><label>Alamat Detail</label><textarea id="address" rows="3" required placeholder="Nama jalan, nomor rumah, dusun/lingkungan">${esc(p.alamat||'')}</textarea></div></div><div class="actions"><button class="primary">Simpan dan Lanjut</button></div></form>`,3);el('cancel-rm').onclick=renderParticipant;el('patient-form').onsubmit=savePatient;loadRegions()}
async function regions(path,select,placeholder){select.disabled=true;select.innerHTML='<option value="">Memuat...</option>';const response=await fetch(`${BASE_API_URL}/${path}`);if(!response.ok)throw new Error('Data wilayah tidak dapat dimuat.');const rows=await response.json();select.innerHTML=`<option value="">${placeholder}</option>`+rows.map(r=>`<option value="${esc(r.id)}" data-name="${esc(r.name)}">${esc(r.name)}</option>`).join('');select.disabled=false}
async function loadRegions(){try{await regions('provinces.json',el('province'),'Pilih provinsi');el('province').onchange=async()=>{await regions(`regencies/${el('province').value}.json`,el('regency'),'Pilih kabupaten/kota');el('district').disabled=true;el('village').disabled=true};el('regency').onchange=async()=>{await regions(`districts/${el('regency').value}.json`,el('district'),'Pilih kecamatan');el('village').disabled=true};el('district').onchange=()=>regions(`villages/${el('district').value}.json`,el('village'),'Pilih kelurahan/desa')}catch(e){showError(e.message)}}
const selectedName=id=>el(id).selectedOptions[0]?.dataset.name||'';async function savePatient(e){e.preventDefault();clearError();const button=e.submitter;button.disabled=true;button.innerHTML='<span class="spinner"></span>Menyimpan';try{const data=await post('{{ route('kiosk.patient.create') }}',{participant_token:state.token,province_name:selectedName('province'),regency_name:selectedName('regency'),district_name:selectedName('district'),village_name:selectedName('village'),alamat_detail:el('address').value});state.patient=data.patient;state.schedules=data.schedules||[];renderQueueForm()}catch(error){showError(error.message);button.disabled=false;button.textContent='Simpan dan Lanjut'}}
function renderQueueForm(){setStage(`${personSummary()}<form id="queue-form" class="queue-card"><div class="stage-header"><div class="section-title" style="margin:0"><div class="step">3</div><div><h2>Pilih Poli dan Dokter</h2><p>Jadwal yang tersedia hari ini</p></div></div><button type="button" id="back-participant" class="secondary back">Kembali</button></div><div class="queue-grid"><div class="field"><label>Poliklinik</label><select id="poli" required><option value="">Pilih poli</option>${state.schedules.map(p=>`<option value="${esc(p.kd_poli)}">${esc(p.nm_poli)}</option>`).join('')}</select></div><div class="field"><label>Dokter</label><select id="doctor" required disabled><option value="">Pilih dokter</option></select></div><button class="primary">Ambil Antrean</button></div></form>`,3);el('back-participant').onclick=renderParticipant;el('poli').onchange=()=>{const poli=state.schedules.find(p=>p.kd_poli===el('poli').value);el('doctor').innerHTML='<option value="">Pilih dokter</option>'+(poli?.doctors||[]).map(d=>`<option value="${esc(d.kd_dokter)}">${esc(d.nm_dokter)} · ${esc(d.jam_mulai)}-${esc(d.jam_selesai)}</option>`).join('');el('doctor').disabled=!poli};el('queue-form').onsubmit=registerQueue}
async function registerQueue(e){e.preventDefault();clearError();const button=e.submitter;button.disabled=true;button.innerHTML='<span class="spinner"></span>Memproses';try{const data=await post('{{ route('kiosk.register') }}',{no_rkm_medis:state.patient.no_rkm_medis,kd_poli:el('poli').value,kd_dokter:el('doctor').value});setStage(`<div class="success">${esc(data.message)}<strong>${esc(data.no_antrean)}</strong><div>No. Rawat ${esc(data.no_rawat)}</div><div class="actions" style="justify-content:center"><button id="finish" class="secondary">Selesai</button></div></div>`,4);el('finish').onclick=()=>location.reload()}catch(error){showError(error.message);button.disabled=false;button.textContent='Ambil Antrean'}}
</script></body></html>
